/**
 * Sermons page, static browse of the transcribed sermon library.
 *
 * Reads the prebuilt catalog (assets/data/sermons_catalog.json, generated by
 * sermon-library/tools/build_sermon_catalog.py) and renders a reverse-chron
 * list. Browsing is fully static: no API call, works even if the backend is
 * asleep. Each row links to the styled transcript page (/transcript.html?v=…).
 *
 * The catalog is already sorted newest-first. The AI-generated `description`
 * (a sermon's Introduction note) is shown when present so a row is evaluable
 * without opening it; sermons not yet enriched simply show title + date.
 */
(function () {
  'use strict';

  var CATALOG_URL = '/assets/data/sermons_catalog.json';
  var listEl = document.getElementById('sx-list');
  var filterEl = document.getElementById('sx-filter');
  var countEl = document.getElementById('sx-count');
  if (!listEl) return;

  var all = [];

  var MONTHS = ['January', 'February', 'March', 'April', 'May', 'June', 'July',
                'August', 'September', 'October', 'November', 'December'];

  function formatDate(yyyymmdd) {
    if (!yyyymmdd || yyyymmdd.length !== 8) return 'Date unknown';
    var y = yyyymmdd.slice(0, 4), m = parseInt(yyyymmdd.slice(4, 6), 10), d = parseInt(yyyymmdd.slice(6, 8), 10);
    if (!m || m < 1 || m > 12) return 'Date unknown';
    return MONTHS[m - 1] + ' ' + d + ', ' + y;
  }

  // Titles arrive like '"A Virtuous Woman"  Ruth 3:11', collapse the double
  // spaces but otherwise leave the pastor's own titling intact.
  function cleanTitle(t) {
    return (t || '').replace(/\s+/g, ' ').trim();
  }

  function escapeHTML(s) {
    return String(s == null ? '' : s).replace(/[&<>"']/g, function (c) {
      return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c];
    });
  }

  function render(items) {
    if (!items.length) {
      listEl.innerHTML = '<p class="sx-empty">No transcripts match that search.</p>';
      countEl.textContent = '';
      return;
    }
    var html = items.map(function (s) {
      var href = '/transcript.html?v=' + encodeURIComponent(s.video_id);
      var desc = s.description
        ? '<p class="sx-card-desc">' + escapeHTML(s.description) + '</p>'
        : '<p class="sx-card-desc sx-card-desc-empty">Transcript available.</p>';
      return (
        '<a class="sx-card" href="' + href + '">' +
          '<div class="sx-card-meta">' +
            '<span class="sx-card-date">' + escapeHTML(formatDate(s.date)) + '</span>' +
          '</div>' +
          '<h2 class="sx-card-title">' +
            (window.boldBibleReference
              ? window.boldBibleReference(cleanTitle(s.title))
              : escapeHTML(cleanTitle(s.title))) +
          '</h2>' +
          desc +
        '</a>'
      );
    }).join('');
    listEl.innerHTML = html;
  }

  function applyFilter() {
    var q = (filterEl && filterEl.value || '').trim().toLowerCase();
    var items = !q ? all : all.filter(function (s) {
      var notes = s.notes || {};
      var hay = [
        s.title || '',
        s.description || '',
        (notes.outline || []).join(' '),
        (notes.themes || []).join(' ')
      ].join(' ').toLowerCase();
      return hay.indexOf(q) !== -1;
    });
    countEl.textContent = q
      ? items.length + ' of ' + all.length + ' transcripts'
      : all.length + ' transcripts';
    render(items);
  }

  fetch(CATALOG_URL)
    .then(function (r) { if (!r.ok) throw new Error('catalog ' + r.status); return r.json(); })
    .then(function (data) {
      all = Array.isArray(data) ? data : [];
      applyFilter();
    })
    .catch(function (err) {
      console.error('Failed to load sermon catalog:', err);
      listEl.innerHTML = '<p class="sx-empty">Sorry, the transcript list could not be loaded right now.</p>';
    });

  if (filterEl) {
    filterEl.addEventListener('input', applyFilter);
  }

  // Floating back-to-top: show once scrolled roughly a screenful down.
  var toTopEl = document.getElementById('sx-totop');
  if (toTopEl) {
    toTopEl.addEventListener('click', function () {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });
    var SHOW_AFTER = 600;
    var ticking = false;
    function syncToTop() {
      ticking = false;
      toTopEl.classList.toggle('is-visible', window.scrollY > SHOW_AFTER);
    }
    window.addEventListener('scroll', function () {
      if (!ticking) { ticking = true; window.requestAnimationFrame(syncToTop); }
    }, { passive: true });
    syncToTop();
  }
})();
